import{_ as e,c as a,o,aj as t}from"./chunks/framework.CLcCQpUA.js";const m=JSON.parse('{"title":"🌏 i18n guide","description":"","frontmatter":{},"headers":[],"relativePath":"dev/i18n.md","filePath":"dev/i18n.md"}'),r={name:"dev/i18n.md"},i=t('<h1 id="🌏-i18n-guide" tabindex="-1">🌏 i18n guide <a class="header-anchor" href="#🌏-i18n-guide" aria-label="Permalink to &quot;🌏 i18n guide&quot;">​</a></h1><p>借助 <a href="https://hosted.weblate.org/engage/comicguispider/" target="_blank" rel="noreferrer">Weblate</a> 托管多语言的翻译</p><p>Translation hosting by <a href="https://hosted.weblate.org/engage/comicguispider/" target="_blank" rel="noreferrer">Weblate</a></p><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to &quot;Development&quot;">​</a></h2><h3 id="ui" tabindex="-1">Ui <a class="header-anchor" href="#ui" aria-label="Permalink to &quot;Ui&quot;">​</a></h3><p>翻译仅需处理单个 yaml 文件如 <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/locale/en-US.yml" target="_blank" rel="noreferrer"><code>en_US.yaml</code></a>，<br> 编译翻译的流程会在客户端使用时自动实现，除下文提及 Usage-ui 的一小点以外无需将精力放编译上<br> 也可以阅读 <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/transfer.py" target="_blank" rel="noreferrer"><code>transfer.py</code></a> 查看编译流程如何生成 res.mo</p><p>Translation only needs to handle single yaml file such as <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/locale/en-US.yml" target="_blank" rel="noreferrer"><code>en_US.yaml</code></a><br> The compilation process of translation will be automatically implemented when the client is used, except for a small point mentioned in Usage-ui, there is no need to focus on compilation You can also read <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/transfer.py" target="_blank" rel="noreferrer"><code>transfer.py</code></a> to see how the res.mo is generated</p><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><p>文档皆存放在 <code>docs</code> 目录里，经由 Github-Action 做成 <code>github pages</code><br> 参考英文的存储路径为 <code>docs/locate/en/*</code></p><p>documents are stored in the <code>docs</code> directory, which will be made into <code>github pages</code> by Github-Action<br> Reference English storage path is <code>docs/locate/en/*</code></p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><h3 id="ui-1" tabindex="-1">ui <a class="header-anchor" href="#ui-1" aria-label="Permalink to &quot;ui&quot;">​</a></h3><p>软件在开启时，会通过 <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/__init__.py" target="_blank" rel="noreferrer"><code>assets/res/__init__.py</code></a> 中的 <code>getUserLanguage</code> 函数获取当前机器的语言如 <code>Chinese (Simplified)_China.utf8</code>（ISO 639-1_ISO 3166-1.encoding）， 检测转换成 RFC1766 标准如 <code>zh-CN</code> ，并加载 *.mo 模块进行语言切换。</p><div class="tip custom-block github-alert"><p class="custom-block-title">若进行了语言开发</p><p>需在 <code>getUserLanguage</code> 中增加对应的 <code>RFC1766</code> 转换，否则默认使用 <code>en-US</code></p></div><p>The software will get the current machine language such as <code>Chinese (Simplified)_China.utf8</code> (ISO 639-1_ISO 3166-1.encoding) through the <code>getUserLanguage</code> function in <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/__init__.py" target="_blank" rel="noreferrer"><code>assets/res/__init__.py</code></a> when it starts, machine language will convert to the RFC1766 standard such as <code>zh-CN</code>, and load the corresponding *.mo module for language switching.</p><div class="tip custom-block github-alert"><p class="custom-block-title">If language development has been carried out</p><p>you need to add the corresponding <code>RFC1766</code> conversion in <code>getUserLanguage</code>, otherwise the default <code>en-US</code> is used</p></div><h3 id="crawler" tabindex="-1">crawler <a class="header-anchor" href="#crawler" aria-label="Permalink to &quot;crawler&quot;">​</a></h3><p>对适用区域为🌏的网站发出的请求会基于 <code>Vars.ua_accept_language</code></p><p>Websites which applicable to 🌏 requests base on <code>Vars.ua_accept_language</code></p><h2 id="contant-us" tabindex="-1">Contant us <a class="header-anchor" href="#contant-us" aria-label="Permalink to &quot;Contant us&quot;">​</a></h2><p>通过 <a href="https://github.com/jasoneri/ComicGUISpider/issues/new?template=feature-request.yml&amp;labels=i18n" target="_blank" rel="noreferrer"><code>issue</code></a> 进行反馈</p><p>feedback by <a href="https://github.com/jasoneri/ComicGUISpider/issues/new?template=feature-request.yml&amp;labels=i18n" target="_blank" rel="noreferrer"><code>issue</code></a></p>',22),n=[i];function s(c,d,l,h,u,p){return o(),a("div",null,n)}const b=e(r,[["render",s]]);export{m as __pageData,b as default};
